<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue";
import type { MerchantApplicationStatus, MerchantApplicationView, PaginatedResult, UserRole } from "@moecraft/shared";
import { apiRequest, uploadFile } from "../../../../api";
import type { MessageKey } from "../../../../i18n";
import { useLocale } from "../../../../i18n";

const props = defineProps<{ roles: UserRole[] }>();
const reviewer = computed(() => props.roles.some((role) => role.startsWith("PLATFORM_")));
const loading = ref(true);
const busy = ref(false);
const error = ref("");
const message = ref("");
const mine = ref<MerchantApplicationView | null>(null);
const queue = ref<MerchantApplicationView[]>([]);
const page = ref(1), pageSize = ref(10), total = ref(0), totalPages = ref(0);
const selected = ref<MerchantApplicationView | null>(null);
const comment = ref("");
const form = reactive({ companyName: "", contactName: "", contactPhone: "", contactEmail: "", businessLicenseNumber: "", qualificationFileIds: [] as string[], agreementAccepted: false });

const { t } = useLocale();
const statusKey = (status: MerchantApplicationStatus): MessageKey => `onboarding.status.${status}`;
const label = (status: MerchantApplicationStatus) => t(statusKey(status));
const reasonTemplates = computed(() => [t("onboarding.reason.blurry"), t("onboarding.reason.mismatch"), t("onboarding.reason.authorization")]);
const editable = computed(() => !mine.value || ["DRAFT", "NEEDS_CHANGES", "REJECTED", "WITHDRAWN"].includes(mine.value.status));
const submittedCount = computed(() => queue.value.filter((item) => item.status === "SUBMITTED").length);
const approvedCount = computed(() => queue.value.filter((item) => item.status === "APPROVED").length);

function copy(item: MerchantApplicationView) { Object.assign(form, { companyName: item.companyName, contactName: item.contactName, contactPhone: item.contactPhone, contactEmail: item.contactEmail, businessLicenseNumber: item.businessLicenseNumber, qualificationFileIds: [...item.qualificationFileIds], agreementAccepted: item.agreementAccepted }); }
function clearFeedback() { error.value = ""; message.value = ""; }
function eventComment(value: string | null) { const keys: Record<string, MessageKey> = { "Application created": "onboarding.event.created", "Application submitted": "onboarding.event.submitted", "Application withdrawn": "onboarding.event.withdrawn" }; return value ? (keys[value] ? t(keys[value]) : value) : ""; }
async function load() { loading.value = true; clearFeedback(); try { if (reviewer.value) { const result = await apiRequest<PaginatedResult<MerchantApplicationView>>(`/merchant-applications?page=${page.value}&pageSize=${pageSize.value}`); queue.value = result.items; ({ total: total.value, totalPages: totalPages.value } = result.pagination); } else { mine.value = await apiRequest<MerchantApplicationView | null>("/merchant-applications/mine"); if (mine.value) copy(mine.value); } } catch { error.value = t("onboarding.feedback.loadError"); } finally { loading.value = false; } }
async function changePage(next: number) { if (next < 1 || next > totalPages.value || next === page.value) return; page.value = next; selected.value = null; await load(); }
async function addFiles(files: FileList | null) { clearFeedback(); for (const file of Array.from(files ?? [])) { try { const asset = await uploadFile<{ id: string }>("merchant-qualification", file); form.qualificationFileIds.push(asset.id); } catch { error.value = t("onboarding.feedback.fileError", { name: file.name }); } } }
async function save() { busy.value = true; clearFeedback(); try { mine.value = await apiRequest<MerchantApplicationView>("/merchant-applications/mine", { method: "PUT", body: JSON.stringify(form) }); copy(mine.value); message.value = t("onboarding.feedback.saved"); } catch { error.value = t("onboarding.feedback.saveError"); } finally { busy.value = false; } }
async function applicantAction(action: "submit" | "withdraw") { busy.value = true; clearFeedback(); try { if (action === "submit") { if (!form.qualificationFileIds.length) { error.value = t("onboarding.feedback.qualificationRequired"); return; } if (!form.agreementAccepted) { error.value = t("onboarding.feedback.agreementRequired"); return; } mine.value = await apiRequest<MerchantApplicationView>("/merchant-applications/mine", { method: "PUT", body: JSON.stringify(form) }); } mine.value = await apiRequest<MerchantApplicationView>(`/merchant-applications/mine/${action}`, { method: "POST" }); copy(mine.value); message.value = t(action === "submit" ? "onboarding.feedback.submitted" : "onboarding.feedback.withdrawn"); } catch { error.value = t("onboarding.feedback.actionError"); } finally { busy.value = false; } }
async function review(decision: "APPROVE" | "REJECT" | "REQUEST_CHANGES") { if (!selected.value) return; busy.value = true; clearFeedback(); try { await apiRequest(`/merchant-applications/${selected.value.id}/review`, { method: "POST", body: JSON.stringify({ decision, comment: comment.value || undefined }) }); selected.value = null; comment.value = ""; message.value = t("onboarding.feedback.reviewed"); await load(); } catch { error.value = t("onboarding.feedback.reviewError"); } finally { busy.value = false; } }
async function merchantStatus(status: "ACTIVE" | "SUSPENDED") { if (!selected.value) return; busy.value = true; clearFeedback(); const id = selected.value.id; try { await apiRequest(`/merchant-applications/${id}/merchant-status`, { method: "POST", body: JSON.stringify({ status, reason: comment.value || t("onboarding.feedback.statusReason") }) }); message.value = t(status === "ACTIVE" ? "onboarding.feedback.resumed" : "onboarding.feedback.suspended"); await load(); selected.value = queue.value.find((item) => item.id === id) ?? null; } catch { error.value = t("onboarding.feedback.statusError"); } finally { busy.value = false; } }
onMounted(load);
</script>

<template>
  <section class="onboarding content-scroll">
    <div class="page-shell">
      <header class="hero">
        <div class="hero-copy"><span class="eyebrow"><i /> MERCHANT CENTER</span><h1>{{ t(reviewer ? "onboarding.reviewerTitle" : "onboarding.applicantTitle") }}</h1><p>{{ t(reviewer ? "onboarding.reviewerSubtitle" : "onboarding.applicantSubtitle") }}</p></div>
        <div v-if="reviewer" class="hero-metrics"><div><b>{{ submittedCount }}</b><span>{{t('onboarding.pendingMetric')}}</span></div><div><b>{{ approvedCount }}</b><span>{{t('onboarding.approvedMetric')}}</span></div></div>
        <div v-else class="hero-steps"><span class="done">1 <small>{{t('onboarding.stepProfile')}}</small></span><i /><span :class="{ done: mine }">2 <small>{{t('onboarding.stepReview')}}</small></span><i /><span :class="{ done: mine?.status === 'APPROVED' }">3 <small>{{t('onboarding.stepOpen')}}</small></span></div>
        <button class="icon-button" :aria-label="t('common.refresh')" :title="t('common.refresh')" @click="load">↻</button>
      </header>

      <transition name="toast"><p v-if="error || message" class="feedback" :class="error ? 'is-error' : 'is-success'" role="status"><span>{{ error ? "!" : "✓" }}</span>{{ error || message }}</p></transition>
      <div v-if="loading" class="loading-card"><span class="spinner" /><p>{{t('common.loading')}}</p></div>

      <template v-else-if="reviewer">
        <div class="review-layout">
          <aside class="application-list">
            <div class="section-heading"><div><span>APPLICATIONS</span><h2>{{t('onboarding.applicationList')}}</h2></div><b>{{ total }}</b></div>
            <div v-if="!queue.length" class="empty-state"><span>◇</span><b>{{t('onboarding.emptyList')}}</b><p>{{t('onboarding.emptyListHint')}}</p></div>
            <button v-for="item in queue" v-else :key="item.id" class="application-item" :class="{ selected: selected?.id === item.id }" @click="selected = item">
              <span class="store-avatar">{{ item.companyName.slice(0, 1) }}</span><span class="item-copy"><b>{{ item.companyName }}</b><small>{{ item.contactName }} · {{ item.contactEmail }}</small></span><em :data-status="item.status">{{ label(item.status) }}</em>
            </button>
            <div v-if="totalPages > 1" class="pagination"><button :disabled="page === 1 || loading" @click="changePage(page - 1)">‹</button><span>{{ page }} / {{ totalPages }}</span><button :disabled="page === totalPages || loading" @click="changePage(page + 1)">›</button></div>
          </aside>

          <main class="review-detail">
            <div v-if="!selected" class="empty-state large"><span>⌁</span><b>{{t('onboarding.selectApplication')}}</b><p>{{t('onboarding.selectApplicationHint')}}</p></div>
            <template v-else>
              <div class="detail-title"><div class="store-avatar large">{{ selected.companyName.slice(0, 1) }}</div><div><span class="status-pill" :data-status="selected.status">{{ label(selected.status) }}</span><h2>{{ selected.companyName }}</h2><p>{{t('common.applicationNumber',{id:selected.id.slice(-8).toUpperCase()})}}</p></div></div>
              <div class="info-grid"><div><span>{{t('onboarding.contact')}}</span><b>{{ selected.contactName }}</b><small>{{ selected.contactPhone }}</small></div><div><span>{{t('onboarding.email')}}</span><b>{{ selected.contactEmail }}</b><small>{{t('onboarding.primaryContact')}}</small></div><div><span>{{t('onboarding.license')}}</span><b>{{ selected.businessLicenseNumber }}</b><small>{{t('onboarding.manualReview')}}</small></div><div><span>{{t('onboarding.qualifications')}}</span><b>{{t('common.fileCount',{count:selected.qualificationFileIds.length})}}</b><small>{{t('onboarding.privateStorage')}}</small></div></div>
              <section class="detail-section"><div class="section-heading"><div><span>HISTORY</span><h3>{{t('onboarding.history')}}</h3></div></div><ol class="audit-timeline"><li v-for="event in selected.timeline" :key="event.id"><i /><div><b>{{ label(event.toStatus) }}</b><span>{{ new Date(event.createdAt).toLocaleString() }}</span><p v-if="event.comment">{{ eventComment(event.comment) }}</p></div></li></ol></section>
              <section class="detail-section decision"><div class="section-heading"><div><span>DECISION</span><h3>{{t('onboarding.decision')}}</h3></div></div><label><span>{{t('onboarding.reviewComment')}}</span><textarea v-model="comment" rows="3" :placeholder="t('onboarding.reviewPlaceholder')" /></label><div v-if="selected.status === 'SUBMITTED'" class="templates"><button v-for="reason in reasonTemplates" :key="reason" @click="comment = reason">＋ {{ reason }}</button></div><div v-if="selected.status === 'SUBMITTED'" class="actions"><button class="button secondary" :disabled="busy" @click="review('REQUEST_CHANGES')">{{t('onboarding.requestChanges')}}</button><button class="button danger" :disabled="busy" @click="review('REJECT')">{{t('onboarding.reject')}}</button><button class="button primary" :disabled="busy" @click="review('APPROVE')">{{t('onboarding.approve')}}</button></div><div v-if="selected.status === 'APPROVED'" class="merchant-control"><div><span>{{t('onboarding.businessStatus')}}</span><b :class="selected.merchantStatus === 'ACTIVE' ? 'online' : 'offline'"><i />{{ t(selected.merchantStatus === 'ACTIVE' ? 'onboarding.active' : 'onboarding.suspended') }}</b></div><button v-if="selected.merchantStatus === 'SUSPENDED'" class="button primary" @click="merchantStatus('ACTIVE')">{{t('onboarding.resume')}}</button><button v-else class="button danger" @click="merchantStatus('SUSPENDED')">{{t('onboarding.suspend')}}</button></div></section>
            </template>
          </main>
        </div>
      </template>

      <template v-else>
        <div v-if="mine" class="status-banner" :data-status="mine.status"><span class="status-icon">{{ mine.status === 'APPROVED' ? '✓' : 'i' }}</span><div><b>{{t('onboarding.statusPrefix',{status:label(mine.status)})}}</b><p>{{ mine.reviewComment || t(mine.status === 'SUBMITTED' ? 'onboarding.statusSubmittedHint' : mine.status === 'APPROVED' ? 'onboarding.statusApprovedHint' : 'onboarding.statusEditableHint') }}</p></div></div>
        <div class="applicant-layout">
          <form class="form-card" @submit.prevent="save">
            <div class="section-heading"><div><span>BUSINESS PROFILE</span><h2>{{t('onboarding.profile')}}</h2><p>{{t('onboarding.profileHint')}}</p></div><span class="required-note">* {{t('common.required')}}</span></div>
            <div class="form-grid"><label><span>{{t('onboarding.companyName')}} *</span><input v-model="form.companyName" :disabled="!editable" required minlength="2" :placeholder="t('onboarding.companyPlaceholder')" /></label><label><span>{{t('onboarding.license')}} *</span><input v-model="form.businessLicenseNumber" :disabled="!editable" required minlength="5" :placeholder="t('onboarding.licensePlaceholder')" /></label></div>
            <div class="divider" />
            <div class="section-heading compact"><div><span>CONTACT</span><h2>{{t('onboarding.contactSection')}}</h2></div></div>
            <div class="form-grid"><label><span>{{t('onboarding.contactName')}} *</span><input v-model="form.contactName" :disabled="!editable" required minlength="2" :placeholder="t('onboarding.contactPlaceholder')" /></label><label><span>{{t('onboarding.phone')}} *</span><input v-model="form.contactPhone" :disabled="!editable" required minlength="6" :placeholder="t('onboarding.phonePlaceholder')" /></label><label class="full"><span>{{t('onboarding.email')}} *</span><input v-model="form.contactEmail" :disabled="!editable" required type="email" :placeholder="t('onboarding.emailPlaceholder')" /></label></div>
            <div class="divider" />
            <div class="section-heading compact"><div><span>QUALIFICATIONS</span><h2>{{t('onboarding.qualificationSection')}}</h2><p>{{t('onboarding.qualificationHint')}}</p></div></div>
            <label class="upload-zone" :class="{ disabled: !editable }"><input :disabled="!editable" type="file" multiple accept="image/jpeg,image/png,image/webp,application/pdf" @change="addFiles(($event.target as HTMLInputElement).files)" /><span class="upload-icon">↥</span><b>{{ t(form.qualificationFileIds.length ? 'onboarding.uploadCount' : 'onboarding.uploadEmpty', {count:form.qualificationFileIds.length}) }}</b><small>{{t('onboarding.uploadPrivateHint')}}</small></label>
            <label class="agreement"><input v-model="form.agreementAccepted" :disabled="!editable" type="checkbox" /><span>{{t('onboarding.agreement')}}</span></label>
            <div class="form-actions"><button v-if="editable" type="button" class="button secondary" :disabled="busy" @click="save">{{t('onboarding.saveDraft')}}</button><button v-if="editable" type="button" class="button primary" :disabled="busy" @click="applicantAction('submit')">{{t('onboarding.submit')}}</button><button v-if="mine && ['DRAFT', 'SUBMITTED', 'NEEDS_CHANGES'].includes(mine.status)" type="button" class="text-button danger-text" :disabled="busy" @click="applicantAction('withdraw')">{{t('onboarding.withdraw')}}</button></div>
          </form>

          <aside class="help-column"><section><span class="help-icon">◎</span><h3>{{t('onboarding.reviewDuration')}}</h3><p>{{t('onboarding.reviewDurationHint')}}</p></section><section><span class="help-icon">◇</span><h3>{{t('onboarding.dataSafety')}}</h3><p>{{t('onboarding.dataSafetyHint')}}</p></section><section v-if="mine?.timeline.length" class="mini-timeline"><h3>{{t('onboarding.progress')}}</h3><ol><li v-for="event in mine.timeline" :key="event.id"><i /><div><b>{{ label(event.toStatus) }}</b><small>{{ new Date(event.createdAt).toLocaleDateString() }}</small></div></li></ol></section></aside>
        </div>
      </template>
    </div>
  </section>
</template>

<style scoped>
.onboarding{--purple:#6957e8;--purple-dark:#5643d4;--purple-soft:#f0edff;color:var(--text);background:linear-gradient(145deg,var(--shell-bg),var(--surface-subtle));}.page-shell{width:min(1320px,100%);margin:0 auto}.hero{position:relative;display:flex;min-height:158px;align-items:center;justify-content:space-between;gap:30px;overflow:hidden;padding:30px 34px;margin-bottom:22px;border:1px solid color-mix(in srgb,var(--purple) 18%,var(--border));border-radius:18px;background:linear-gradient(112deg,color-mix(in srgb,var(--purple-soft) 80%,var(--surface)) 0%,var(--surface) 58%);box-shadow:0 16px 45px rgb(45 37 110 / 8%)}.hero::after{position:absolute;width:300px;height:300px;right:-95px;top:-155px;border:48px solid color-mix(in srgb,var(--purple) 8%,transparent);border-radius:50%;content:""}.hero-copy{position:relative;z-index:1;max-width:580px}.eyebrow{display:flex;align-items:center;gap:8px;color:var(--purple);font-size:11px;font-weight:700;letter-spacing:.16em}.eyebrow i{width:7px;height:7px;border-radius:50%;background:var(--purple);box-shadow:0 0 0 5px color-mix(in srgb,var(--purple) 12%,transparent)}h1{margin:10px 0 8px;color:var(--text);font-size:clamp(25px,3vw,38px);line-height:1.15;letter-spacing:-.035em}.hero p{max-width:560px;margin:0;color:var(--text-secondary);font-size:14px;line-height:1.7}.hero-steps{position:relative;z-index:1;display:flex;align-items:center;gap:10px}.hero-steps>span{display:grid;width:38px;height:38px;place-items:center;border:1px solid var(--border);border-radius:50%;background:var(--surface);color:var(--text-muted);font-weight:700}.hero-steps>span.done{border-color:var(--purple);background:var(--purple);color:white}.hero-steps>span small{position:absolute;margin-top:70px;color:var(--text-muted);font-size:11px;font-weight:500;white-space:nowrap}.hero-steps>i{width:54px;height:1px;background:var(--border)}.hero-metrics{position:relative;z-index:1;display:flex;gap:12px}.hero-metrics div{display:grid;min-width:96px;padding:14px 18px;border:1px solid var(--border);border-radius:12px;background:color-mix(in srgb,var(--surface) 82%,transparent);text-align:center}.hero-metrics b{color:var(--purple);font-size:25px}.hero-metrics span{color:var(--text-muted);font-size:11px}.icon-button{position:relative;z-index:2;display:grid;width:38px;height:38px;place-items:center;border:1px solid var(--border);border-radius:10px;background:var(--surface);color:var(--text-secondary);font-size:20px;cursor:pointer}.feedback{display:flex;align-items:center;gap:10px;padding:13px 16px;margin:0 0 18px;border:1px solid;border-radius:10px;font-size:13px}.feedback>span{display:grid;width:22px;height:22px;place-items:center;border-radius:50%;color:white}.is-error{border-color:color-mix(in srgb,var(--danger) 35%,var(--border));background:var(--danger-soft);color:var(--danger)}.is-error>span{background:var(--danger)}.is-success{border-color:color-mix(in srgb,var(--success) 35%,var(--border));background:var(--success-soft);color:var(--success)}.is-success>span{background:var(--success)}.loading-card,.empty-state{display:grid;min-height:220px;place-items:center;align-content:center;gap:10px;color:var(--text-muted);text-align:center}.spinner{width:30px;height:30px;border:3px solid var(--border);border-top-color:var(--purple);border-radius:50%;animation:spin .8s linear infinite}.status-banner{display:flex;align-items:center;gap:14px;padding:15px 18px;margin-bottom:18px;border:1px solid var(--border);border-left:4px solid var(--purple);border-radius:12px;background:var(--surface)}.status-banner[data-status="APPROVED"]{border-left-color:var(--success)}.status-banner[data-status="REJECTED"],.status-banner[data-status="NEEDS_CHANGES"]{border-left-color:var(--danger)}.status-icon{display:grid;width:34px;height:34px;place-items:center;border-radius:10px;background:var(--purple-soft);color:var(--purple);font-weight:700}.status-banner b{font-size:14px}.status-banner p{margin:4px 0 0;color:var(--text-muted);font-size:12px}.applicant-layout{displ